  malphite: { diff: "EVEN", tone: "#e8b84b", tldr: "Bait his R \u2014 Q-zone, out-scale his poke.", breakdown: "Bait his R, Q-zone his step-ups, build a little armor, and out-scale him.", dos: ["Bait his R", "Q-zone his poke", "Out-scale and R-execute"], donts: ["Auto into his W", "Eat his R knockup", "Fall behind in scaling"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Un-dodgeable dash. Bait it.", winT: "ULT DOWN", winS: "Q-W + R him." }, hold: "Hold W to silence his combo and Q to peel \u2014 bait his R, then zone and out-scale.", tip: "Bait his R, Q-zone his poke, and out-scale him \u2014 your R-execute beats his low kill pressure.", win: "Bait his R and out-scale him." },
  maokai: { diff: "EVEN", tone: "#e8b84b", tldr: "Silence his root \u2014 Q-zone, out-scale him.", breakdown: "W-silence his combo, dodge his W root, and out-scale his low-threat tank kit.", dos: ["W-silence his combo", "Dodge his W root", "Out-scale and R-execute"], donts: ["Get rooted into his combo", "Fight in saplings", "Eat his R knockback"], key: { slot: "W", name: "Twisted Advance (Root)", cd: "11s", note: "His lock-on root. Silence around it.", winT: "ROOT DOWN", winS: "Q-W + R him." }, hold: "Hold W to silence his combo and Q to peel his W root follow-up.", tip: "W-silence his combo and dodge his root \u2014 out-scale his low-threat tank kit with R + HP.", win: "Silence his combo and out-scale him." },
