  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 silence her in the shroud, out-scale her.", breakdown: "Build MR, W-silence her (the cone hits her in shroud), and out-scale her burst.", dos: ["Build MR", "W-silence her in the shroud", "Out-scale and R-execute"], donts: ["Fight her 6 with no MR", "Get Q-poked down", "Chase her into shroud"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable, but your W cone still silences her.", winT: "SHROUD DOWN", winS: "Q-W + R her." }, hold: "Hold W to silence her \u2014 your cone silences her even inside her shroud, shutting off her combo.", tip: "Your W is a cone, not a target \u2014 silence her inside the shroud to cut her burst, build MR, and out-scale.", win: "Silence her in the shroud, out-scale her." },
