  quinn: { diff: "TRICKY", tone: "#ff8b3d", tldr: "She pokes + kites \u2014 Q-zone, all-in early.", breakdown: "Quinn out-pokes you. Q-zone, W-silence her, and all-in early before she scales.", dos: ["Q-zone her step-ups", "W-silence her", "All-in early"], donts: ["Fight into her blind", "Poke-war from range", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Q-peel after it.", winT: "VAULT DOWN", winS: "Q-W + R her." }, hold: "Hold W to silence her and Q to peel \u2014 cut her combo before she kites away.", tip: "Q-zone her poke and W-silence her \u2014 all-in her early before she out-scales you with kiting.", win: "Q-zone her and all-in early." },
