  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 silence his combo, dodge his E.", breakdown: "Build MR, W-silence his combo, dodge his E root, and out-scale his drain.", dos: ["Build MR", "W-silence his combo", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Fall behind in scaling"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Zone around it.", winT: "ASCENSION DOWN", winS: "Q-W + R him." }, hold: "Hold W to silence his combo \u2014 cut his E-root-into-W before his drain starts.", tip: "Build MR, W-silence his combo, and dodge his E root \u2014 out-scale his drain with R + HP.", win: "Build MR and silence his combo." },
