  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — silence his combo and out-scale with Feast stacks.","breakdown":"Akshan plays around Heroic Swing. Land Q under his feet as Heroic Swing comes down, W-silence the answer, and every Feast stack makes the next all-in worse for him. Doran’s Shield blunts the poke war.","dos":["Q-knockup when Heroic Swing is down","W-silence his combo","Feast stacks on every reset"],"donts":["Stand still for his Heroic Swing","Burn W on nothing","Fall behind on R stacks"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Q-knockup + Feast the kill."},"win":"Silence his combo and out-scale with Feast stacks."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then silence his combo and out-scale with Feast stacks.","breakdown":"Cassiopeia plays around Miasma. Land Q under his feet as Miasma comes down, W-silence the answer, and every Feast stack makes the next all-in worse for him. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Q-knockup when Miasma is down","W-silence his combo","Feast stacks on every reset"],"donts":["Stand still for his Miasma","Burn W on nothing","Fall behind on R stacks"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Q-knockup + Feast the kill."},"win":"Silence his combo and out-scale with Feast stacks."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — silence his combo and out-scale with Feast stacks.","breakdown":"Galio plays around Justice Punch. Land Q under his feet as Justice Punch comes down, W-silence the answer, and every Feast stack makes the next all-in worse for him. Take Mercs / MR shard — his damage is magic.","dos":["Q-knockup when Justice Punch is down","W-silence his combo","Feast stacks on every reset"],"donts":["Stand still for his Justice Punch","Burn W on nothing","Fall behind on R stacks"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"Q-knockup + Feast the kill."},"win":"Silence his combo and out-scale with Feast stacks."},
  graves: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Bait his key tool — silence his combo and out-scale with Feast stacks.","breakdown":"Graves plays around Quickdraw. Land Q under his feet as Quickdraw comes down, W-silence the answer, and every Feast stack makes the next all-in worse for him.","dos":["Q-knockup when Quickdraw is down","W-silence his combo","Feast stacks on every reset"],"donts":["Stand still for his Quickdraw","Burn W on nothing","Fall behind on R stacks"],"key":{"slot":"E","name":"Quickdraw","cd":"13s","note":"His dash + armor stacks. Engage when it's down.","winT":"QUICKDRAW DOWN","winS":"Q-knockup + Feast the kill."},"win":"Silence his combo and out-scale with Feast stacks."},
